#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a[51],b=0,c=0,m=0,l,r;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        m+=a[i];
    }
    cin>>l>>r;
    if(r*n<m || m<l*n)cout<<-1;
    else{
        for(int i=1;i<=n;i++){
            if(a[i]>r)b+=a[i]-r;
            else if(a[i]<l)c+=l-a[i];
        }
        cout<<max(b,c);
    }
    return 0;
}
